"use client"

import { useInfiniteHits, useStats, useInstantSearch, useCurrentRefinements, Highlight } from "react-instantsearch"
import { PriceTag } from "@/components/tcg/PriceTag"
import { GameBadge } from "@/components/tcg/GameBadge"
import { SearchResultsSkeleton } from "./SearchResultsSkeleton"
import { SearchNoResults } from "./SearchNoResults"
import { SearchFilteredNoResults } from "./SearchFilteredNoResults"
import { SearchFilters } from "./SearchFilters"
import Link from "next/link"
import type { Hit } from "instantsearch.js"

// ─── Types ─────────────────────────────────────────────────────────────────────

type AlgoliaHit = Hit<{
  name: string
  set_name: string
  set_code: string
  game: string
  rarity: string | null
  image_url: string | null
  lowest_price: number | null
  seller_count: number
  card_id: string
}>

// ─── Hit card component ────────────────────────────────────────────────────────

function AlgoliaCardHit({ hit }: { hit: AlgoliaHit }) {
  return (
    <Link
      href={`/cards/${hit.card_id}`}
      className="group block rounded-[14px] overflow-hidden border border-border transition-all duration-150 hover:border-border-strong"
      style={{ background: "var(--bg-surface-1, #18162A)", padding: 12 }}
    >
      {/* Card image */}
      <div
        className="aspect-[5/7] overflow-hidden rounded-[10px] border border-border mb-2.5"
        style={{ background: "var(--bg-surface-3, #2C2A4A)" }}
      >
        {hit.image_url ? (
          <img
            src={hit.image_url}
            alt={hit.name}
            className="w-full h-full object-cover [@media(pointer:fine)]:group-hover:scale-105 transition-transform"
          />
        ) : (
          <div className="w-full h-full flex items-center justify-center">
            <span className="text-xs text-tertiary">No image</span>
          </div>
        )}
      </div>

      {/* Card info */}
      <div style={{ padding: "0 2px" }}>
        <GameBadge gameCode={hit.game} compact className="mb-1" />
        <p className="font-barlow leading-tight line-clamp-2 mb-0.5 text-sm font-semibold text-primary">
          <Highlight attribute="name" hit={hit} />
        </p>
        <p className="truncate mb-1.5 text-xs text-secondary">
          {hit.set_name}
        </p>
        <PriceTag price={hit.lowest_price} sellerCount={hit.seller_count} variant="compact" />
      </div>
    </Link>
  )
}

// ─── CardSearchGrid ────────────────────────────────────────────────────────────

/**
 * Shared sidebar + card grid layout.
 * Renders the SearchFilters sidebar (280px) and the card hit grid (flex-1).
 * Used by both CardBrowsingPage and the search page.
 */
export function CardSearchGrid() {
  const { hits, isLastPage, showMore } = useInfiniteHits<AlgoliaHit>()
  const { nbHits, query } = useStats()
  const { status, results } = useInstantSearch()
  const { items: refinementItems } = useCurrentRefinements()

  const activeFilterCount = refinementItems.reduce((sum, item) => sum + item.refinements.length, 0)
  const hasActiveFilters = activeFilterCount > 0

  const isLoading = status === "loading" || status === "stalled"
  const isInitialLoading = isLoading && hits.length === 0
  const isNoResults = !isLoading && nbHits === 0

  return (
    <div
      data-testid="card-search-grid"
      style={{ display: "flex", minHeight: 900 }}
    >
      {/* Desktop sidebar — always mounted */}
      <SearchFilters activeFilterCount={activeFilterCount} />

      {/* Main content */}
      <div style={{ flex: 1, minWidth: 0, padding: "20px 24px" }}>
        {isInitialLoading ? (
          <SearchResultsSkeleton />
        ) : isNoResults ? (
          hasActiveFilters ? (
            <SearchFilteredNoResults
              onClearFilters={() => {
                setTimeout(() => {
                  for (const item of refinementItems) {
                    for (const refinement of item.refinements) {
                      item.refine(refinement)
                    }
                  }
                }, 0)
              }}
            />
          ) : (
            <SearchNoResults query={query} queryAfterRemoval={results?.queryAfterRemoval} />
          )
        ) : (
          <>
            {/* Card grid */}
            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 2xl:grid-cols-5 3xl:grid-cols-6 4xl:grid-cols-8 gap-4">
              {hits.map((hit) => (
                <AlgoliaCardHit key={hit.objectID} hit={hit} />
              ))}
            </div>

            {/* Load more */}
            {!isLastPage && (
              <div className="mt-8 flex justify-center">
                <button
                  onClick={showMore}
                  disabled={isLoading}
                  className="px-6 py-2.5 rounded-xl text-sm font-medium transition-colors"
                  style={{
                    border: "1.5px solid var(--border)",
                    background: "var(--bg-surface-2, #21203A)",
                    color: "var(--text-secondary, #B8B0D8)",
                    cursor: isLoading ? "default" : "pointer",
                    opacity: isLoading ? 0.5 : 1,
                  }}
                >
                  {isLoading ? "Loading…" : "Load more cards"}
                </button>
              </div>
            )}
          </>
        )}
      </div>
    </div>
  )
}

"use client"

import { cn } from "@/lib/utils"

interface Props {
  currentPage: number
  totalPages: number
  totalResults: number
  onPageChange: (page: number) => void
  loading?: boolean
}

export function Pagination({ currentPage, totalPages, totalResults, onPageChange, loading = false }: Props) {
  if (totalPages <= 1) {
    return null
  }

  const getVisiblePages = () => {
    const delta = 2
    const pages: (number | string)[] = []
    
    // Always show first page
    pages.push(1)
    
    // Calculate range around current page
    const start = Math.max(2, currentPage - delta)
    const end = Math.min(totalPages - 1, currentPage + delta)
    
    // Add ellipsis after first page if needed
    if (start > 2) {
      pages.push('...')
    }
    
    // Add pages around current page
    for (let i = start; i <= end; i++) {
      pages.push(i)
    }
    
    // Add ellipsis before last page if needed
    if (end < totalPages - 1) {
      pages.push('...')
    }
    
    // Always show last page (if different from first)
    if (totalPages > 1) {
      pages.push(totalPages)
    }
    
    return pages
  }

  const visiblePages = getVisiblePages()

  return (
    <div className="flex flex-col sm:flex-row items-center justify-between gap-4 p-4 bg-white border border-gray-200 rounded-lg">
      {/* Results info */}
      <div className="text-sm text-gray-600">
        Showing page {currentPage} of {totalPages} ({totalResults.toLocaleString()} total results)
      </div>

      {/* Pagination controls */}
      <div className="flex items-center space-x-1">
        {/* Previous button */}
        <button
          onClick={() => onPageChange(currentPage - 1)}
          disabled={currentPage === 1 || loading}
          className={cn(
            "px-3 py-2 text-sm font-medium rounded-md transition-colors duration-200",
            currentPage === 1 || loading
              ? "text-gray-400 cursor-not-allowed"
              : "text-gray-700 hover:bg-gray-100"
          )}
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
          </svg>
        </button>

        {/* Page numbers */}
        <div className="flex items-center space-x-1">
          {visiblePages.map((page, index) => {
            if (page === '...') {
              return (
                <span key={`ellipsis-${index}`} className="px-2 py-2 text-sm text-gray-500">
                  ...
                </span>
              )
            }

            const pageNum = page as number
            const isActive = pageNum === currentPage

            return (
              <button
                key={pageNum}
                onClick={() => onPageChange(pageNum)}
                disabled={loading}
                className={cn(
                  "px-3 py-2 text-sm font-medium rounded-md transition-colors duration-200",
                  isActive
                    ? "bg-blue-600 text-white"
                    : "text-gray-700 hover:bg-gray-100 disabled:text-gray-400"
                )}
              >
                {pageNum}
              </button>
            )
          })}
        </div>

        {/* Next button */}
        <button
          onClick={() => onPageChange(currentPage + 1)}
          disabled={currentPage === totalPages || loading}
          className={cn(
            "px-3 py-2 text-sm font-medium rounded-md transition-colors duration-200",
            currentPage === totalPages || loading
              ? "text-gray-400 cursor-not-allowed"
              : "text-gray-700 hover:bg-gray-100"
          )}
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
          </svg>
        </button>
      </div>

      {/* Jump to page */}
      <div className="flex items-center space-x-2">
        <label htmlFor="jump-page" className="text-sm text-gray-600 whitespace-nowrap">
          Go to:
        </label>
        <input
          id="jump-page"
          type="number"
          min={1}
          max={totalPages}
          placeholder={currentPage.toString()}
          disabled={loading}
          className="w-16 px-2 py-1 text-sm border border-gray-300 rounded focus:ring-blue-500 focus:border-blue-500 disabled:bg-gray-100"
          onKeyDown={(e) => {
            if (e.key === 'Enter') {
              const target = e.target as HTMLInputElement
              const page = parseInt(target.value)
              if (page >= 1 && page <= totalPages) {
                onPageChange(page)
                target.value = ''
              }
            }
          }}
        />
      </div>
    </div>
  )
}

"use client"

import { useState, useEffect } from "react"
import { useStats, useSearchBox, Configure } from "react-instantsearch"
import { InstantSearchNext } from "react-instantsearch-nextjs"
import { UiState } from "instantsearch.js"
import { algoliaClient, CARDS_INDEX, CARDS_INDEX_PRICE_ASC, CARDS_INDEX_PRICE_DESC } from "@/lib/algolia"
import { ActiveFilterChips } from "./ActiveFilterChips"
import { SortControl } from "./SortControl"
import { CardSearchGrid } from "./CardSearchGrid"

// ─── URL state mapping ────────────────────────────────────────────────────────

const SORT_TO_PARAM: Record<string, string> = {
  [CARDS_INDEX]:           "relevance",
  [CARDS_INDEX_PRICE_ASC]: "price-asc",
  [CARDS_INDEX_PRICE_DESC]:"price-desc",
}
const PARAM_TO_SORT: Record<string, string> = Object.fromEntries(
  Object.entries(SORT_TO_PARAM).map(([k, v]) => [v, k])
)

export function createCardsStateMapping() {
  return {
    stateToRoute(uiState: UiState): Record<string, unknown> {
      const idx = uiState[CARDS_INDEX] ?? {}
      const route: Record<string, unknown> = {}
      if (idx.query)        route.q        = idx.query
      const facets = idx.refinementList ?? {}
      if (facets.game?.length)      route.game      = facets.game
      if (facets.rarity?.length)    route.rarity    = facets.rarity
      if (facets.condition?.length) route.condition = facets.condition
      if (facets.set_name?.length)  route.set       = facets.set_name
      if (facets.language?.length)  route.language  = facets.language
      const numeric = idx.numericMenu ?? {}
      if (numeric.lowest_price)     route.price     = numeric.lowest_price
      if (idx.sortBy && idx.sortBy !== CARDS_INDEX) {
        route.sort = SORT_TO_PARAM[idx.sortBy] ?? idx.sortBy
      }
      return route
    },
    routeToState(routeState: Record<string, unknown>): UiState {
      const toArr = (v: unknown): string[] => v ? [v].flat() as string[] : []
      const refinementList: Record<string, string[]> = {
        game:      toArr(routeState.game),
        rarity:    toArr(routeState.rarity),
        condition: toArr(routeState.condition),
        set_name:  toArr(routeState.set),
        language:  toArr(routeState.language),
      }
      return {
        [CARDS_INDEX]: {
          query:          (routeState.q as string) ?? "",
          refinementList,
          numericMenu:    routeState.price ? { lowest_price: routeState.price as string } : undefined,
          sortBy:         routeState.sort ? (PARAM_TO_SORT[routeState.sort as string] ?? undefined) : undefined,
        },
      }
    },
  }
}

// ─── Inline search bar ────────────────────────────────────────────────────────

function SearchBar() {
  const { query, refine } = useSearchBox()
  const [inputValue, setInputValue] = useState(query)

  useEffect(() => { setInputValue(query) }, [query])

  return (
    <div className="mb-4">
      <input
        type="search"
        value={inputValue}
        onChange={(e) => {
          setInputValue(e.target.value)
          setTimeout(() => refine(e.target.value), 0)
        }}
        placeholder="Search cards by name, set, or artist…"
        className="w-full rounded-2xl px-5 py-3 text-sm"
        style={{
          border: "1px solid var(--border)",
          background: "rgba(24, 22, 42, 0.60)",
          backdropFilter: "blur(12px)",
          color: "var(--text-primary, #F0EEFF)",
          outline: "none",
        }}
      />
    </div>
  )
}

// ─── Results body (inside InstantSearchNext context) ──────────────────────────

function ResultsBody({ initialQuery }: { initialQuery: string }) {
  const { nbHits, query } = useStats()
  const isLoading = false // Lightweight — actual loading state is in CardSearchGrid

  return (
    <>
      {/* Inline search bar — full width above chips+sort row */}
      <SearchBar />

      {/* Result count — above chips row */}
      {query && (
        <p className="text-[13px] mb-2 text-secondary">
          <span className="font-semibold text-primary">
            {nbHits.toLocaleString()}
          </span>{" "}results for &quot;{query}&quot;
        </p>
      )}

      {/* Filter chips + sort — same full-width row, above sidebar+grid */}
      <div className="flex items-center gap-2 mb-4 min-w-0">
        <div className="flex-1 min-w-0">
          <ActiveFilterChips />
        </div>
        <div className="hidden md:block flex-shrink-0 ml-auto">
          <SortControl />
        </div>
      </div>

      {/* Shared sidebar+grid layout */}
      <CardSearchGrid />
    </>
  )
}

// ─── Public component ─────────────────────────────────────────────────────────

interface AlgoliaSearchResultsProps {
  initialQuery: string
  initialGame?: string
}

export function AlgoliaSearchResults({ initialQuery, initialGame }: AlgoliaSearchResultsProps) {
  return (
    <InstantSearchNext
      searchClient={algoliaClient}
      indexName={CARDS_INDEX}
      routing={{ stateMapping: createCardsStateMapping() }}
      initialUiState={{ [CARDS_INDEX]: { query: initialQuery, refinementList: { game: initialGame ? [initialGame] : [], rarity: [], condition: [], set_name: [], language: [] } } }}
    >
      <Configure hitsPerPage={20} />
      <ResultsBody initialQuery={initialQuery} />
    </InstantSearchNext>
  )
}

import { cn } from "@/lib/utils"

export const CONDITION_COLORS: Record<string, { border: string; text: string; bg: string }> = {
  NM:  { border: 'border-green-500/30',  text: 'text-green-400',  bg: 'bg-green-500/10'  },
  LP:  { border: 'border-lime-400/30',   text: 'text-lime-400',   bg: 'bg-lime-400/10'   },
  MP:  { border: 'border-yellow-400/30', text: 'text-yellow-400', bg: 'bg-yellow-400/10' },
  HP:  { border: 'border-red-500/30',    text: 'text-red-400',    bg: 'bg-red-500/10'    },
  DMG: { border: 'border-orange-500/30', text: 'text-orange-400', bg: 'bg-orange-500/10' },
}

export function getConditionChipClasses(
  condition: string,
  state: 'selected' | 'unselected' | 'disabled',
): string {
  const colors = CONDITION_COLORS[condition] ?? CONDITION_COLORS['NM']
  if (state === 'disabled') {
    return cn(colors.border, colors.text, 'opacity-30 cursor-not-allowed border-dashed')
  }
  if (state === 'selected') {
    return cn(colors.bg, colors.border, colors.text)
  }
  return cn(colors.border, colors.text, 'opacity-60 hover:opacity-100')
}

"use client"

import { useState } from "react"
import { Configure } from "react-instantsearch"
import { InstantSearchNext } from "react-instantsearch-nextjs"
import { algoliaClient, CARDS_INDEX } from "@/lib/algolia"
import { createCardsStateMapping } from "@/components/search/AlgoliaSearchResults"
import { CardSearchGrid } from "@/components/search/CardSearchGrid"
import { BrowseBreadcrumbs } from "./BrowseBreadcrumbs"
import { GameSelectorStrip, GAME_STRIP_ITEMS } from "./GameSelectorStrip"
import { CategoryPills } from "./CategoryPills"
import { PopularSetsCarousel } from "./PopularSetsCarousel"
import { ResultsBar } from "./ResultsBar"
import { BrowsePageGameTracker } from "./BrowsePageGameTracker"

interface Props {
  initialQuery?: string
  initialGame?: string
}

export function CardBrowsingPage({ initialQuery, initialGame }: Props) {
  return (
    <InstantSearchNext
      searchClient={algoliaClient}
      indexName={CARDS_INDEX}
      routing={{ stateMapping: createCardsStateMapping() }}
      initialUiState={{
        [CARDS_INDEX]: {
          query: initialQuery ?? "",
          refinementList: {
            game: initialGame ? [initialGame] : [],
            rarity: [],
            condition: [],
            set_name: [],
            language: [],
          },
        },
      }}
    >
      <Configure hitsPerPage={20} />
      <BrowsePageContent initialGame={initialGame ?? null} />
    </InstantSearchNext>
  )
}

// ─── Inner content (needs InstantSearch context) ───────────────────────────────

function BrowsePageContent({ initialGame }: { initialGame: string | null }) {
  const [activeGame, setActiveGame] = useState<string | null>(initialGame)

  return (
    <div>
      {/* Breadcrumbs */}
      <BrowseBreadcrumbs />

      {/* Game Selector Strip */}
      <GameSelectorStrip />

      {/* Track active game for child components */}
      <BrowsePageGameTracker onGameChange={setActiveGame} />

      {/* Category Quick Links — hidden on mobile */}
      <div className="hidden md:block">
        <CategoryPills />
      </div>

      {/* Popular Sets Carousel — hidden on mobile */}
      <div className="hidden md:block">
        <PopularSetsCarousel gameCode={activeGame} />
      </div>

      {/* Results Bar */}
      <ResultsBar />

      {/* Sidebar + Grid */}
      <CardSearchGrid />

      {/* Trending Cards section — placeholder for T02 */}
      <div
        data-testid="trending-section-placeholder"
        style={{ minHeight: 1 }}
      />

      {/* Seller CTA Banner — placeholder for T02 */}
      <div
        data-testid="cta-section-placeholder"
        style={{ minHeight: 1 }}
      />
    </div>
  )
}

"use client"

import { useGridColumns } from "@/hooks/useGridColumns"

interface Props {
  viewMode?: 'grid' | 'list'
  count?: number
}

export function CardGridSkeleton({ viewMode = 'grid', count = 24 }: Props) {
  const { gridClass, columns } = useGridColumns()
  
  // Adjust skeleton count based on grid columns for better UX
  const adjustedCount = Math.max(count, columns * 3) // Show at least 3 rows

  if (viewMode === 'list') {
    return (
      <div className="space-y-4">
        {Array.from({ length: adjustedCount }).map((_, i) => (
          <div key={i} className="flex items-center space-x-4 p-4 bg-card rounded-lg border border-border animate-pulse">
            <div className="flex-shrink-0 w-16 card-aspect bg-muted rounded" />
            <div className="flex-1 space-y-2">
              <div className="h-4 bg-muted rounded w-3/4" />
              <div className="h-3 bg-muted rounded w-1/2" />
              <div className="h-3 bg-muted rounded w-1/4" />
            </div>
            <div className="flex-shrink-0 space-y-2">
              <div className="h-6 w-12 bg-muted rounded" />
              <div className="h-3 w-16 bg-muted rounded" />
            </div>
          </div>
        ))}
      </div>
    )
  }

  return (
    <div className={gridClass}>
      {Array.from({ length: adjustedCount }).map((_, i) => (
        <div key={i} className="bg-card rounded-lg border border-border animate-pulse">
          <div className="card-aspect w-full bg-muted rounded-t-lg" />
          <div className="p-3 space-y-2">
            <div className="h-4 bg-muted rounded" />
            <div className="h-3 bg-muted rounded w-3/4" />
            <div className="h-3 bg-muted rounded w-1/2" />
          </div>
        </div>
      ))}
    </div>
  )
}

export function SearchResultsSkeleton() {
  return (
    <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-4">
      {Array.from({ length: 20 }).map((_, i) => (
        <div
          key={i}
          data-testid="skeleton-card"
          className="rounded-[14px] overflow-hidden animate-pulse p-3"
          style={{ background: "var(--bg-surface-1, #18162A)", border: "1px solid var(--border)" }}
        >
          <div
            className="w-full aspect-[5/7] rounded-[10px]"
            style={{ background: "var(--bg-surface-3, #2C2A4A)" }}
          />
          <div className="pt-2.5 space-y-2">
            <div className="h-3 rounded" style={{ background: "var(--bg-surface-3, #2C2A4A)", width: "80%" }} />
            <div className="h-3 rounded" style={{ background: "var(--bg-surface-3, #2C2A4A)", width: "55%" }} />
          </div>
        </div>
      ))}
    </div>
  )
}

interface SearchFilteredNoResultsProps {
  onClearFilters: () => void
}

export function SearchFilteredNoResults({ onClearFilters }: SearchFilteredNoResultsProps) {
  return (
    <div role="status" aria-live="polite" style={{ textAlign: "center", padding: "48px 16px" }}>
      <h3 style={{ fontSize: 16, fontWeight: 600, color: "var(--text-primary, #F0EEFF)", marginBottom: 8 }}>
        No cards match these filters
      </h3>
      <p style={{ fontSize: 13, color: "var(--text-secondary, #B8B0D8)", marginBottom: 20 }}>
        Try removing some filters to see more results.
      </p>
      <button
        onClick={onClearFilters}
        style={{
          fontSize: 13,
          padding: "8px 20px",
          borderRadius: 8,
          border: "1.5px solid var(--interactive, #8B5CF6)",
          background: "transparent",
          color: "var(--interactive, #8B5CF6)",
          cursor: "pointer",
        }}
      >
        Clear All Filters
      </button>
    </div>
  )
}

import { render, screen } from '@testing-library/react'
import { describe, it, expect, vi, beforeEach } from 'vitest'
import React from 'react'

// ─── Mocks ────────────────────────────────────────────────────────────────────

vi.mock('@/lib/algolia', () => ({
  algoliaClient: {},
  CARDS_INDEX: 'test_cards',
  CARDS_INDEX_PRICE_ASC: 'test_cards_price_asc',
  CARDS_INDEX_PRICE_DESC: 'test_cards_price_desc',
}))

// Mock InstantSearchNext to just render children (no real Algolia)
vi.mock('react-instantsearch-nextjs', () => ({
  InstantSearchNext: ({ children }: { children: React.ReactNode }) => (
    <div data-testid="instant-search-provider">{children}</div>
  ),
}))

// Mock next/navigation (used by SearchFilters → PricePresets)
vi.mock('next/navigation', () => ({
  useParams: () => ({ locale: 'en' }),
  useRouter: () => ({ push: vi.fn(), replace: vi.fn(), back: vi.fn() }),
  usePathname: () => '/cards',
  useSearchParams: () => new URLSearchParams(),
}))

// Mock react-instantsearch hooks used by sub-components
vi.mock('react-instantsearch', () => ({
  Configure: () => null,
  useRefinementList: () => ({ items: [], refine: vi.fn() }),
  useStats: () => ({ nbHits: 42 }),
  useInstantSearch: () => ({ status: 'idle', results: {} }),
  useCurrentRefinements: () => ({ items: [] }),
  useInfiniteHits: () => ({ hits: [], isLastPage: true, showMore: vi.fn() }),
  useSortBy: () => ({ currentRefinement: 'test_cards', refine: vi.fn() }),
  useSearchBox: () => ({ query: '', refine: vi.fn() }),
  useNumericMenu: () => ({ items: [], refine: vi.fn() }),
  Highlight: ({ hit, attribute }: any) => <span>{hit?.[attribute] ?? ''}</span>,
}))

// ─── Component under test ─────────────────────────────────────────────────────

import { CardBrowsingPage } from '../CardBrowsingPage'

describe('CardBrowsingPage', () => {
  beforeEach(() => {
    vi.clearAllMocks()
