"use client"

import { useState, useEffect } from "react"

export interface GridColumnsInfo {
  columns: number
  gridClass: string
}

/**
 * Hook to track the current number of grid columns based on viewport width
 * Returns the column count and corresponding Tailwind grid class
 */
export function useGridColumns(): GridColumnsInfo {
  // Better initial state based on typical viewport
  const getInitialState = (): GridColumnsInfo => {
    if (typeof window === 'undefined') {
      return {
        columns: 2,
        gridClass: "grid grid-cols-2 gap-4"
      }
    }
    
    const width = window.innerWidth
    if (width < 640) {
      return {
        columns: 2,
        gridClass: "grid grid-cols-2 gap-4"
      }
    }
    
    return {
      columns: 4,
      gridClass: "grid grid-cols-4 gap-4"
    }
  }
  
  const [gridInfo, setGridInfo] = useState<GridColumnsInfo>(getInitialState())

  useEffect(() => {
    const updateGridInfo = () => {
      if (typeof window === 'undefined') return

      const width = window.innerWidth
      let columns: number

      // Progressive column scaling based on width
      // Samsung S23 viewport is typically 360-412px depending on browser chrome
      if (width < 360) {
        // Very small mobile: 1 column (only very old phones)
        columns = 1
      } else if (width < 640) {
        // Mobile: 2 columns (covers all modern phones 360-640px)
        columns = 2
      } else if (width < 768) {
        // Small tablets: 3 columns
        columns = 3
      } else if (width < 1024) {
        // Medium screens: 4 columns
        columns = 4
      } else if (width < 1400) {
        // Large screens: 5 columns
        columns = 5
      } else if (width < 2600) {
        // Extra large screens like 2560x1440: 6 columns
        columns = 6
      } else if (width < 3000) {
        // Ultra-wide screens: 7 columns
        columns = 7
      } else if (width < 3200) {
        // Massive displays: 8 columns
        columns = 8
      } else {
        // Extreme displays: 10 columns
        columns = 10
      }

      // Use Tailwind's standard grid classes that are guaranteed to exist
      let gridClass: string
      if (columns >= 10) {
        gridClass = "grid grid-cols-10 gap-4"
      } else if (columns >= 8) {
        gridClass = "grid grid-cols-8 gap-4"
      } else if (columns >= 7) {
        gridClass = "grid grid-cols-7 gap-4"
      } else if (columns >= 6) {
        gridClass = "grid grid-cols-6 gap-4"  // Standard Tailwind class
      } else if (columns >= 5) {
        gridClass = "grid grid-cols-5 gap-4"  // Standard Tailwind class
      } else if (columns >= 4) {
        gridClass = "grid grid-cols-4 gap-4"  // Standard Tailwind class
      } else if (columns >= 3) {
        gridClass = "grid grid-cols-3 gap-4"  // Standard Tailwind class
      } else if (columns >= 2) {
        gridClass = "grid grid-cols-2 gap-4"  // Standard Tailwind class
      } else {
        gridClass = "grid grid-cols-1 gap-4"  // Standard Tailwind class
      }
      
      setGridInfo({ columns, gridClass })
    }

    // Initial calculation
    updateGridInfo()

    // Listen for viewport changes with more aggressive debouncing for mobile
    let timeoutId: NodeJS.Timeout
    const handleResize = () => {
      // Debounce resize events to avoid too many updates
      // Use longer debounce on mobile to prevent column switching during scroll
      clearTimeout(timeoutId)
      const debounceTime = window.innerWidth < 768 ? 300 : 150
      timeoutId = setTimeout(updateGridInfo, debounceTime)
    }

    window.addEventListener('resize', handleResize)
    return () => {
      clearTimeout(timeoutId)
      window.removeEventListener('resize', handleResize)
    }
  }, [])

  return gridInfo
}

"use client"

import { cn } from "@/lib/utils"

const GAME_COLORS: Record<string, string> = {
  MTG:     "var(--game-mtg)",
  POKEMON: "var(--game-pokemon)",
  YUGIOH:  "var(--game-yugioh)",
  OPTCG:   "var(--game-optcg)",
}

const GAME_LABELS: Record<string, string> = {
  MTG: "MTG",
  POKEMON: "Pokémon",
  YUGIOH: "Yu-Gi-Oh!",
  OPTCG: "One Piece",
}

interface GameBadgeProps {
  gameCode: string
  compact?: boolean
  className?: string
}

export function GameBadge({ gameCode, compact = false, className }: GameBadgeProps) {
  const code = gameCode.toUpperCase()
  const color = GAME_COLORS[code] ?? "var(--muted-foreground)"
  const label = compact ? code.slice(0, 3) : (GAME_LABELS[code] ?? gameCode)

  return (
    <span
      className={cn(
        "inline-flex items-center px-1.5 py-0.5 rounded-full",
        "text-[10px] font-bold uppercase tracking-wide",
        className
      )}
      style={{
        color,
        backgroundColor: `color-mix(in srgb, ${color} 12%, transparent)`,
        border: `1px solid color-mix(in srgb, ${color} 25%, transparent)`,
      }}
    >
      {label}
    </span>
  )
}

