import { describe, it, expect, vi, beforeEach } from 'vitest'
import { render, screen } from '@testing-library/react'

// ─── Mocks ────────────────────────────────────────────────────────────────────

let capturedInstantSearchProps: any = null
vi.mock('@/lib/algolia', () => ({
  algoliaClient: {},
  CARDS_INDEX: 'test_cards',
  CARDS_INDEX_PRICE_ASC: 'test_cards_price_asc',
  CARDS_INDEX_PRICE_DESC: 'test_cards_price_desc',
}))

let mockHits: any[] = []
let mockNbHits = 0
let mockQuery = ''
let mockStatus: string = 'idle'
let mockRefinementItems: any[] = []
let mockIsLastPage = false
let mockShowMore = vi.fn()

vi.mock('react-instantsearch', () => ({
  useInfiniteHits: () => ({ hits: mockHits, isLastPage: mockIsLastPage, showMore: mockShowMore }),
  useStats: () => ({ nbHits: mockNbHits, query: mockQuery }),
  useInstantSearch: () => ({ status: mockStatus, results: { queryAfterRemoval: undefined } }),
  useSearchBox: () => ({ refine: vi.fn(), query: mockQuery }),
  useCurrentRefinements: () => ({ items: mockRefinementItems }),
  Configure: () => null,
  Pagination: () => <div data-testid="pagination" />,
  Highlight: ({ hit, attribute }: any) => <span>{hit[attribute]}</span>,
  InstantSearch: ({ children }: any) => <div>{children}</div>,
}))

vi.mock('../SearchFilters', () => ({
  SearchFilters: ({ activeFilterCount }: any) => (
    <div data-testid="search-filters" data-count={activeFilterCount} />
  ),
}))

vi.mock('../ActiveFilterChips', () => ({
  ActiveFilterChips: () => <div data-testid="active-filter-chips" />,
}))

vi.mock('../SortControl', () => ({
  SortControl: () => <div data-testid="sort-control" />,
}))

vi.mock('../SearchFilteredNoResults', () => ({
  SearchFilteredNoResults: ({ onClearFilters }: any) => (
    <div data-testid="search-filtered-no-results" onClick={onClearFilters} />
  ),
}))

vi.mock('react-instantsearch-nextjs', () => ({
  InstantSearchNext: (props: any) => {
    capturedInstantSearchProps = props
    return <div>{props.children}</div>
  },
}))

vi.mock('@/components/cards/CardHoverProvider', () => ({
  CardHoverProvider: ({ children }: any) => <>{children}</>,
  useCardHover: () => ({ showHoverAtPosition: vi.fn(), hideHover: vi.fn(), isMobile: false }),
}))

vi.mock('next/navigation', () => ({
  useRouter: () => ({ push: vi.fn() }),
  useSearchParams: () => new URLSearchParams(),
}))

// ─── Tests ───────────────────────────────────────────────────────────────────

import { AlgoliaSearchResults, createCardsStateMapping } from '../AlgoliaSearchResults'
import { SearchNoResults } from '../SearchNoResults'
import { SearchResultsSkeleton } from '../SearchResultsSkeleton'
import { CARDS_INDEX, CARDS_INDEX_PRICE_ASC, CARDS_INDEX_PRICE_DESC } from '@/lib/algolia'

describe('SearchResultsSkeleton', () => {
  it('renders 20 shimmer card placeholders', () => {
    render(<SearchResultsSkeleton />)
    const skeletons = screen.getAllByTestId('skeleton-card')
    expect(skeletons).toHaveLength(20)
  })

  it('uses a responsive grid layout', () => {
    const { container } = render(<SearchResultsSkeleton />)
    const grid = container.firstChild as HTMLElement
    expect(grid.className).toMatch(/grid/)
  })
})

describe('SearchNoResults', () => {
  it('shows generic empty state when no query correction', () => {
    render(<SearchNoResults query="xzqabc" queryAfterRemoval={undefined} />)
    expect(screen.getByText(/no results/i)).toBeInTheDocument()
  })

  it('shows "Did you mean?" when queryAfterRemoval differs from query', () => {
    render(<SearchNoResults query="charizrd" queryAfterRemoval="charizard" />)
    expect(screen.getByText(/did you mean/i)).toBeInTheDocument()
    expect(screen.getByText(/charizard/i)).toBeInTheDocument()
  })

  it('has role="alert" on the Did you mean banner', () => {
    render(<SearchNoResults query="charizrd" queryAfterRemoval="charizard" />)
    expect(screen.getByRole('alert')).toBeInTheDocument()
  })

  it('does not show "Did you mean?" when queryAfterRemoval equals query', () => {
    render(<SearchNoResults query="charizard" queryAfterRemoval="charizard" />)
    expect(screen.queryByText(/did you mean/i)).not.toBeInTheDocument()
  })
})

describe('AlgoliaSearchResults', () => {
  beforeEach(() => {
    vi.clearAllMocks()
    mockHits = []
    mockNbHits = 0
    mockQuery = ''
    mockStatus = 'idle'
    mockRefinementItems = []
    mockIsLastPage = false
    mockShowMore = vi.fn()
    capturedInstantSearchProps = null
  })

  it('renders skeleton on initial load (no hits) while keeping filters mounted', () => {
    mockStatus = 'loading'
    mockHits = []
    render(<AlgoliaSearchResults initialQuery="" />)
    expect(screen.getAllByTestId('skeleton-card').length).toBeGreaterThan(0)
    // Filter widgets stay mounted during loading
    expect(screen.getByTestId('search-filters')).toBeInTheDocument()
    expect(screen.getByTestId('active-filter-chips')).toBeInTheDocument()
    expect(screen.getByTestId('sort-control')).toBeInTheDocument()
  })

  it('does not replace existing hits with skeleton during Load More (no flicker)', () => {
    mockStatus = 'loading'
    mockHits = [{ objectID: 'print-0', name: 'Pikachu', card_id: 'card-0', game: 'POKEMON', set_name: 'Base Set', set_code: 'BS', rarity: 'Common', image_url: null, lowest_price: null, seller_count: 0 }]
    mockIsLastPage = false
    render(<AlgoliaSearchResults initialQuery="" />)
    expect(screen.queryAllByTestId('skeleton-card')).toHaveLength(0)
    expect(screen.getByText('Pikachu')).toBeInTheDocument()
  })

  it('renders hit count when results are available', () => {
    mockStatus = 'idle'
    mockNbHits = 847
    mockQuery = 'charizard'
    mockHits = Array.from({ length: 5 }, (_, i) => ({
      objectID: `print-${i}`,
      name: `Card ${i}`,
      card_id: `card-${i}`,
      game: 'POKEMON',
      set_name: 'Test Set',
      set_code: 'TST',
      rarity: 'Common',
      image_url: null,
      lowest_price: null,
      seller_count: 0,
    }))
    render(<AlgoliaSearchResults initialQuery="charizard" />)
    expect(screen.getByText(/847/)).toBeInTheDocument()
    expect(screen.getByText(/charizard/i)).toBeInTheDocument()
  })

  it('renders card names from hits', () => {
    mockStatus = 'idle'
    mockNbHits = 1
    mockHits = [{
      objectID: 'print-001',
      name: 'Charizard VSTAR',
      card_id: 'card-001',
      game: 'POKEMON',
      set_name: 'Brilliant Stars',
      set_code: 'BRS',
      rarity: 'Rare',
      image_url: null,
      lowest_price: null,
      seller_count: 0,
    }]
    render(<AlgoliaSearchResults initialQuery="charizard" />)
    expect(screen.getByText('Charizard VSTAR')).toBeInTheDocument()
  })

  it('renders SearchNoResults when nbHits is 0 and not loading', () => {
    mockStatus = 'idle'
    mockNbHits = 0
    mockQuery = 'xzqabc'
    mockHits = []
    render(<AlgoliaSearchResults initialQuery="xzqabc" />)
    expect(screen.getByText(/no results/i)).toBeInTheDocument()
  })

  it('passes a routing prop to InstantSearchNext', () => {
    render(<AlgoliaSearchResults initialQuery="charizard" />)
    expect(capturedInstantSearchProps).not.toBeNull()
    expect(capturedInstantSearchProps.routing).toBeDefined()
  })

  it('sets initialUiState.refinementList.game when initialGame provided (AC5)', () => {
    render(<AlgoliaSearchResults initialQuery="" initialGame="POKEMON" />)
    expect(capturedInstantSearchProps.initialUiState[CARDS_INDEX].refinementList.game).toEqual(['POKEMON'])
  })

  it('sets initialUiState.refinementList.game to empty array when no initialGame', () => {
    render(<AlgoliaSearchResults initialQuery="" />)
    expect(capturedInstantSearchProps.initialUiState[CARDS_INDEX].refinementList?.game ?? []).toEqual([])
  })

  it('renders SearchFilters inside the layout', () => {
    render(<AlgoliaSearchResults initialQuery="" />)
    expect(screen.getByTestId('search-filters')).toBeInTheDocument()
  })

  it('renders ActiveFilterChips', () => {
    render(<AlgoliaSearchResults initialQuery="" />)
    expect(screen.getByTestId('active-filter-chips')).toBeInTheDocument()
  })

  it('renders SortControl', () => {
    render(<AlgoliaSearchResults initialQuery="" />)
    expect(screen.getByTestId('sort-control')).toBeInTheDocument()
  })

  it('renders SearchFilteredNoResults when nbHits is 0 and refinements are active', () => {
    mockStatus = 'idle'
    mockNbHits = 0
    mockQuery = 'charizard'
    mockRefinementItems = [{ attribute: 'game', refinements: [{ label: 'MTG', value: 'MTG' }] }]
    render(<AlgoliaSearchResults initialQuery="charizard" />)
    expect(screen.getByTestId('search-filtered-no-results')).toBeInTheDocument()
    expect(screen.queryByText(/no results/i)).not.toBeInTheDocument()
  })

  it('renders SearchNoResults when nbHits is 0 and no refinements are active', () => {
    mockStatus = 'idle'
    mockNbHits = 0
    mockQuery = 'xzqabc'
    mockRefinementItems = []
    render(<AlgoliaSearchResults initialQuery="xzqabc" />)
    expect(screen.getByText(/no results/i)).toBeInTheDocument()
    expect(screen.queryByTestId('search-filtered-no-results')).not.toBeInTheDocument()
  })

  it('renders SearchFilteredNoResults when nbHits is 0 with active filters and no query', () => {
    mockStatus = 'idle'
    mockNbHits = 0
    mockQuery = ''
    mockRefinementItems = [{ attribute: 'game', refinements: [{ label: 'MTG', value: 'MTG' }] }]
    render(<AlgoliaSearchResults initialQuery="" />)
    expect(screen.getByTestId('search-filtered-no-results')).toBeInTheDocument()
  })

  it('passes activeFilterCount to SearchFilters based on refinement count', () => {
    mockRefinementItems = [
      { attribute: 'game', refinements: [{ label: 'MTG', value: 'MTG' }, { label: 'POKEMON', value: 'POKEMON' }] },
      { attribute: 'condition', refinements: [{ label: 'NM', value: 'NM' }] },
    ]
    render(<AlgoliaSearchResults initialQuery="" />)
    const filters = screen.getByTestId('search-filters')
    expect(filters).toHaveAttribute('data-count', '3')
  })

  it('renders Load More button when isLastPage is false', () => {
    mockStatus = 'idle'
    mockNbHits = 40
    mockIsLastPage = false
    mockHits = Array.from({ length: 20 }, (_, i) => ({
      objectID: `print-${i}`,
      name: `Card ${i}`,
      card_id: `card-${i}`,
      game: 'POKEMON',
      set_name: 'Test Set',
      set_code: 'TST',
      rarity: 'Common',
      image_url: null,
      lowest_price: null,
      seller_count: 0,
    }))
    render(<AlgoliaSearchResults initialQuery="" />)
    expect(screen.getByRole('button', { name: /load more cards/i })).toBeInTheDocument()
  })

  it('hides Load More button when isLastPage is true', () => {
    mockStatus = 'idle'
    mockNbHits = 5
    mockIsLastPage = true
    mockHits = Array.from({ length: 5 }, (_, i) => ({
      objectID: `print-${i}`,
      name: `Card ${i}`,
      card_id: `card-${i}`,
      game: 'POKEMON',
      set_name: 'Test Set',
      set_code: 'TST',
      rarity: 'Common',
      image_url: null,
      lowest_price: null,
      seller_count: 0,
    }))
    render(<AlgoliaSearchResults initialQuery="" />)
    expect(screen.queryByRole('button', { name: /load more cards/i })).not.toBeInTheDocument()
  })

  it('renders SearchBar input', () => {
    render(<AlgoliaSearchResults initialQuery="" />)
    expect(screen.getByPlaceholderText(/search cards by name/i)).toBeInTheDocument()
  })

  it('card grid has wide-screen responsive column classes', () => {
    mockHits = [{ objectID: '1', name: 'Test Card', game: 'mtg', set_name: 'Test Set' }]
    mockNbHits = 1
    mockStatus = 'idle'
    const { container } = render(<AlgoliaSearchResults />)
    // The grid div is the direct parent of the card hits
    const grids = container.querySelectorAll('.grid')
    const cardGrid = Array.from(grids).find(el =>
      el.className.includes('grid-cols-4') || el.className.includes('grid-cols-2')
    ) as HTMLElement | undefined
    expect(cardGrid).toBeDefined()
    expect(cardGrid!.className).toContain('2xl:grid-cols-5')
    expect(cardGrid!.className).toContain('3xl:grid-cols-6')
    expect(cardGrid!.className).toContain('4xl:grid-cols-8')
  })
})

describe('createCardsStateMapping', () => {
  const { stateToRoute, routeToState } = createCardsStateMapping()

  describe('stateToRoute', () => {
    it('maps query to ?q=', () => {
      const route = stateToRoute({ [CARDS_INDEX]: { query: 'pikachu' } })
      expect(route.q).toBe('pikachu')
    })

    it('maps game refinements to ?game=', () => {
      const route = stateToRoute({ [CARDS_INDEX]: { refinementList: { game: ['POKEMON'] } } })
      expect(route.game).toEqual(['POKEMON'])
    })

    it('maps condition refinements to ?condition=', () => {
      const route = stateToRoute({ [CARDS_INDEX]: { refinementList: { condition: ['NM', 'LP'] } } })
      expect(route.condition).toEqual(['NM', 'LP'])
    })

    it('maps set_name to ?set=', () => {
      const route = stateToRoute({ [CARDS_INDEX]: { refinementList: { set_name: ['Obsidian Flames'] } } })
      expect(route.set).toEqual(['Obsidian Flames'])
    })

    it('maps rarity refinements to ?rarity=', () => {
      const route = stateToRoute({ [CARDS_INDEX]: { refinementList: { rarity: ['Rare', 'Mythic'] } } })
      expect(route.rarity).toEqual(['Rare', 'Mythic'])
    })

    it('maps language refinements to ?language=', () => {
      const route = stateToRoute({ [CARDS_INDEX]: { refinementList: { language: ['English'] } } })
      expect(route.language).toEqual(['English'])
    })

    it('maps price-asc sort to ?sort=price-asc', () => {
      const route = stateToRoute({ [CARDS_INDEX]: { sortBy: CARDS_INDEX_PRICE_ASC } })
      expect(route.sort).toBe('price-asc')
    })

    it('maps price-desc sort to ?sort=price-desc', () => {
      const route = stateToRoute({ [CARDS_INDEX]: { sortBy: CARDS_INDEX_PRICE_DESC } })
      expect(route.sort).toBe('price-desc')
    })

    it('omits sort param when relevance (default index)', () => {
      const route = stateToRoute({ [CARDS_INDEX]: { sortBy: CARDS_INDEX } })
      expect(route.sort).toBeUndefined()
    })

    it('omits empty query', () => {
      const route = stateToRoute({ [CARDS_INDEX]: { query: '' } })
      expect(route.q).toBeUndefined()
    })
  })

  describe('routeToState', () => {
    it('maps ?q= to query', () => {
      const state = routeToState({ q: 'charizard' })
      expect(state[CARDS_INDEX].query).toBe('charizard')
    })

    it('maps ?game= to refinementList.game (string → array)', () => {
      const state = routeToState({ game: 'POKEMON' })
      expect(state[CARDS_INDEX].refinementList?.game).toEqual(['POKEMON'])
    })

    it('maps ?condition= array to refinementList.condition', () => {
      const state = routeToState({ condition: ['NM', 'LP'] })
      expect(state[CARDS_INDEX].refinementList?.condition).toEqual(['NM', 'LP'])
    })

    it('maps ?set= to refinementList.set_name', () => {
      const state = routeToState({ set: ['Obsidian Flames'] })
      expect(state[CARDS_INDEX].refinementList?.set_name).toEqual(['Obsidian Flames'])
    })

    it('maps ?rarity= to refinementList.rarity', () => {
      const state = routeToState({ rarity: ['Rare'] })
      expect(state[CARDS_INDEX].refinementList?.rarity).toEqual(['Rare'])
    })

    it('maps ?language= to refinementList.language', () => {
      const state = routeToState({ language: 'English' })
      expect(state[CARDS_INDEX].refinementList?.language).toEqual(['English'])
    })

    it('always includes all facet attributes even when empty', () => {
      const state = routeToState({})
      const facets = state[CARDS_INDEX].refinementList!
      expect(facets.game).toEqual([])
      expect(facets.rarity).toEqual([])
      expect(facets.condition).toEqual([])
      expect(facets.set_name).toEqual([])
      expect(facets.language).toEqual([])
    })

    it('maps ?sort=price-asc to sortBy index', () => {
      const state = routeToState({ sort: 'price-asc' })
      expect(state[CARDS_INDEX].sortBy).toBe(CARDS_INDEX_PRICE_ASC)
    })

    it('defaults query to empty string when no q param', () => {
      const state = routeToState({})
      expect(state[CARDS_INDEX].query).toBe('')
    })
  })
})

